import React, { useState, useEffect, useRef } from 'react';

export default function App() {
  const [c, setC] = useState(2);
  const [x, setX] = useState(1);
  const [n, setN] = useState(2);
  const [isDragging, setIsDragging] = useState(null);
  const [animatedResult, setAnimatedResult] = useState(4);
  const svgRef = useRef(null);

  const derivative = n === 0 ? 0 : c * n * Math.pow(x, n - 1);
  const functionValue = c * Math.pow(x, n);

  useEffect(() => {
    const target = derivative;
    const interval = setInterval(() => {
      setAnimatedResult(prev => {
        const diff = target - prev;
        if (Math.abs(diff) < 0.01) return target;
        return prev + diff * 0.15;
      });
    }, 16);
    return () => clearInterval(interval);
  }, [derivative]);

  const width = 420, height = 260;
  const padding = { left: 35, right: 15, top: 15, bottom: 25 };
  const plotW = width - padding.left - padding.right;
  const plotH = height - padding.top - padding.bottom;

  const xMin = -2, xMax = 2;
  const yMin = -2, yMax = 2;

  const toScreenX = (val) => padding.left + ((val - xMin) / (xMax - xMin)) * plotW;
  const toScreenY = (val) => padding.top + ((yMax - val) / (yMax - yMin)) * plotH;
  const fromScreenX = (px) => xMin + ((px - padding.left) / plotW) * (xMax - xMin);

  const curvePath = [];
  for (let i = 0; i <= 100; i++) {
    const cx = xMin + (i / 100) * (xMax - xMin);
    const cy = c * Math.pow(cx, n);
    if (cy >= yMin && cy <= yMax) {
      curvePath.push(`${curvePath.length === 0 ? 'M' : 'L'} ${toScreenX(cx)} ${toScreenY(cy)}`);
    }
  }

  const tangentLen = (xMax - xMin) * 0.25;
  const tx1 = x - tangentLen / 2, tx2 = x + tangentLen / 2;
  const ty1 = functionValue + derivative * (tx1 - x);
  const ty2 = functionValue + derivative * (tx2 - x);

  const handleMouseMove = (e) => {
    if (isDragging !== 'chart' || !svgRef.current) return;
    const rect = svgRef.current.getBoundingClientRect();
    const newX = fromScreenX(e.clientX - rect.left);
    setX(Math.round(Math.max(-2, Math.min(2, newX)) * 10) / 10);
  };

  const handleSliderDrag = (setter, min, max, step = 0.1) => (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const pct = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    setter(Math.round((min + pct * (max - min)) / step) * step);
  };

  return (
    <div style={styles.container} onMouseUp={() => setIsDragging(null)} onMouseLeave={() => setIsDragging(null)}>
      <h1 style={styles.title}>Derivative of a Polynomial</h1>
      <p style={styles.intro}>The derivative tells you the <strong>slope</strong> at any point.</p>

      <div style={styles.functionDisplay}>
        <span style={styles.funcLabel}>f(x) = </span>
        <span style={styles.coef}>{c}</span> · x<sup style={styles.exp}>{n}</sup>
      </div>

      <div style={styles.chartAndControls}>
        <div style={styles.chartSection}>
          <svg ref={svgRef} width={width} height={height} style={styles.chart} onMouseDown={() => setIsDragging('chart')} onMouseMove={handleMouseMove}>
            <line x1={toScreenX(0)} y1={padding.top} x2={toScreenX(0)} y2={height - padding.bottom} stroke="#334155" />
            <line x1={padding.left} y1={toScreenY(0)} x2={width - padding.right} y2={toScreenY(0)} stroke="#334155" />
            <path d={curvePath.join(' ')} fill="none" stroke="#3b82f6" strokeWidth="3" />
            <line x1={toScreenX(tx1)} y1={toScreenY(ty1)} x2={toScreenX(tx2)} y2={toScreenY(ty2)} stroke="#22c55e" strokeWidth="2" strokeDasharray="5,3" />
            <circle cx={toScreenX(x)} cy={toScreenY(functionValue)} r={8} fill="#f97316" stroke="#fff" strokeWidth="2" style={{cursor: 'grab'}} />
            <text x={toScreenX(tx2) + 5} y={toScreenY(ty2)} fill="#22c55e" fontSize="11" fontWeight="600">slope={derivative.toFixed(1)}</text>
          </svg>
          <div style={styles.hint}>Drag the point to change x</div>
        </div>

        <div style={styles.controls}>
          {[
            { label: 'c = coefficient', val: c, set: setC, min: -5, max: 5, step: 0.5, color: '#3b82f6' },
            { label: 'n = exponent', val: n, set: setN, min: 0, max: 5, step: 1, color: '#a855f7' },
            { label: 'x = input', val: x, set: setX, min: -2, max: 2, step: 0.1, color: '#f97316' }
          ].map((ctrl, i) => (
            <div key={i} style={styles.controlRow}>
              <div style={styles.controlLabel}>{ctrl.label}</div>
              <div style={styles.sliderRow}>
                <div style={styles.sliderTrack} onMouseDown={() => setIsDragging(ctrl.label)} onMouseMove={(e) => isDragging === ctrl.label && handleSliderDrag(ctrl.set, ctrl.min, ctrl.max, ctrl.step)(e)}>
                  <div style={{...styles.sliderFill, width: `${((ctrl.val - ctrl.min) / (ctrl.max - ctrl.min)) * 100}%`, background: ctrl.color}} />
                  <div style={{...styles.sliderHandle, left: `${((ctrl.val - ctrl.min) / (ctrl.max - ctrl.min)) * 100}%`, background: ctrl.color}} />
                </div>
                <div style={styles.controlValue}>{ctrl.step >= 1 ? ctrl.val : ctrl.val.toFixed(1)}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div style={styles.mathSection}>
        <div style={styles.mathTitle}>The Power Rule</div>
        <div style={styles.ruleBox}>d/dx [ c · x<sup>n</sup> ] = c · n · x<sup>n-1</sup></div>
        <div style={styles.computation}>
          <div style={styles.compStep}><div style={styles.stepLabel}>c</div><div style={styles.stepVal}>{c}</div></div>
          <span style={styles.op}>×</span>
          <div style={styles.compStep}><div style={styles.stepLabel}>n</div><div style={styles.stepVal}>{n}</div></div>
          <span style={styles.op}>×</span>
          <div style={styles.compStep}><div style={styles.stepLabel}>x<sup>{n-1}</sup></div><div style={styles.stepVal}>{n === 0 ? 0 : Math.pow(x, n-1).toFixed(2)}</div></div>
          <span style={styles.op}>=</span>
          <div style={styles.result}><div style={styles.resultLabel}>Derivative</div><div style={styles.resultVal}>{animatedResult.toFixed(2)}</div></div>
        </div>
        {n === 0 && <div style={styles.special}>When n=0, the function is constant, so derivative = 0</div>}
      </div>

      <div style={styles.interpret}>
        {derivative > 0 ? <span>Derivative is <strong style={{color:'#22c55e'}}>positive</strong> — function is increasing at x={x.toFixed(1)}</span> :
         derivative < 0 ? <span>Derivative is <strong style={{color:'#ef4444'}}>negative</strong> — function is decreasing at x={x.toFixed(1)}</span> :
         <span>Derivative is <strong style={{color:'#eab308'}}>zero</strong> — function is flat at x={x.toFixed(1)}</span>}
      </div>
    </div>
  );
}

